locale.setlocale(locale.LC_ALL, '')

def normalize_date(date_str):
    for fmt in ('%m/%d/%Y', '%Y-%m-%d', '%B %d, %Y'):
        try:
            return datetime.strptime(date_str, fmt).date().isoformat()
        except ValueError:
            continue
    raise ValueError(f"Date format not recognized: {date_str}")

def normalize_price(price_str):
    # Remove currency symbols and commas
    price_str = re.sub(r'[^\d.,-]', '', price_str)

    # Handle European format
    if ',' in price_str and '.' in price_str:
        price_str = price_str.replace('.', '').replace(',', '.')
    elif ',' in price_str:
        price_str = price_str.replace(',', '')

    try:
        return float(price_str)
    except ValueError:
        raise ValueError(f"Price format not recognized: {price_str}")

def process_csv(input_file, output_file):
    with open(input_file, 'r', encoding='utf-8', errors='ignore') as infile, \
         open(output_file, 'w', newline='', encoding='utf-8') as outfile:

        reader = csv.reader(infile, delimiter=';')
        writer = csv.writer(outfile, delimiter=',')

        for row in reader:
            new_row = []
            for field in row:
                try:
                    # Normalize dates
                    if re.match(r'\d{1,2}/\d{1,2}/\d{4}', field) or \
                       re.match(r'\d{4}-\d{2}-\d{2}', field) or \
                       re.match(r'[A-Za-z]+ \d{1,2}, \d{4}', field):
                        new_row.append(normalize_date(field))
                    # Normalize prices
                    elif re.match(r'[\d,.\$]+', field):
                        new_row.append(normalize_price(field))
                    else:
                        new_row.append(field)
                except ValueError as e:
                    print(f"Error processing field '{field}': {e}")
                    new_row.append(field)
            writer.writerow(new_row)

# Example usage
process_csv('input.csv', 'output.csv')
